.circularIndex <- function(x, n) {
  if (length(x) != 1) {
    stop("'x' must be a single integer")
  }
  if (!is.numeric(x)) {
    stop("'x' must be numeric")
  }
  if (is.na(x)) {
    return(NA_integer_)
  }
  x <- as.integer(x)
  if (x > 0 && x <= n) {
    return(x)
  }
  if (x == 0 || x == n + 1) {
    return(n)
  }
  if (x < 0 && abs(x) <= n) {
    return(n + x + 1)
  }
  if (x > n + 1) {
    return(1L)
  }
  if (x < -n) {
    return(n)
  }
  x
}
